using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["appName"] = "ConfigMcpServer",
        ["version"] = "1.0.0",
        ["maxRetries"] = 3,
        ["timeoutSeconds"] = 30,
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["notifications"] = true,
            ["betaFeatures"] = false
        }
    };

    [McpServerResource(UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(UriTemplate = "config://features",
        Name = "Feature Flags",
        MimeType = "application/json"),
     Description("Returns the current feature flag settings.")]
    public static string GetFeatureFlags() =>
        JsonSerializer.Serialize(AppConfig["features"], new JsonSerializerOptions { WriteIndented = true });
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Looks up a specific configuration key and returns its value.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. 'appName', 'maxRetries')")] string key)
    {
        var config = new Dictionary<string, object>
        {
            ["appName"] = "ConfigMcpServer",
            ["version"] = "1.0.0",
            ["maxRetries"] = 3,
            ["timeoutSeconds"] = 30
        };

        return config.TryGetValue(key, out var value)
            ? JsonSerializer.Serialize(value)
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }

    [McpServerTool, Description("Validates whether a configuration key exists and returns its type.")]
    public static string ValidateConfigKey(
        [Description("The configuration key to validate")] string key)
    {
        var config = new Dictionary<string, object>
        {
            ["appName"] = "ConfigMcpServer",
            ["version"] = "1.0.0",
            ["maxRetries"] = 3,
            ["timeoutSeconds"] = 30
        };

        if (!config.TryGetValue(key, out var value))
            return $"Invalid: key '{key}' does not exist.";

        return $"Valid: key '{key}' exists with type '{value.GetType().Name}' and value '{value}'.";
    }
}

